const express = require('express');
const bodyParser = require('body-parser');
const jwt = require('jsonwebtoken');
const redis = require('redis');
const uuid = require('uuid');

const app = express();
const client = redis.createClient();

const ACCESS_TOKEN_SECRET = 'youraccesstokensecret';
const REFRESH_TOKEN_SECRET = 'yourrefreshtokensecret';
const ACCESS_TOKEN_EXPIRATION = '15m';
const REFRESH_TOKEN_EXPIRATION = 365 * 24 * 60 * 60; // 1 year in seconds

app.use(bodyParser.json());

app.post('/token', (req, res) => {
  const { username, password } = req.body;
  if (username === 'user' && password === 'pass') {
    const userId = uuid.v4();
    const accessToken = jwt.sign({ userId }, ACCESS_TOKEN_SECRET, { expiresIn: ACCESS_TOKEN_EXPIRATION });
    const refreshToken = jwt.sign({ userId }, REFRESH_TOKEN_SECRET);
    
    client.setex(refreshToken, REFRESH_TOKEN_EXPIRATION, userId, (err) => {
      if (err) return res.sendStatus(500);
      res.json({ accessToken, refreshToken });
    });
  } else {
    res.sendStatus(401);
  }
});

app.post('/token/refresh', (req, res) => {
  const { refreshToken } = req.body;
  if (!refreshToken) return res.sendStatus(401);

  client.get(refreshToken, (err, userId) => {
    if (err || !userId) return res.sendStatus(403);

    jwt.verify(refreshToken, REFRESH_TOKEN_SECRET, (err, payload) => {
      if (err) return res.sendStatus(403);

      const accessToken = jwt.sign({ userId: payload.userId }, ACCESS_TOKEN_SECRET, { expiresIn: ACCESS_TOKEN_EXPIRATION });
      res.json({ accessToken });
    });
  });
});

app.listen(3000, () => {
  console.log('Authorization server running on port 3000');
});